import React from 'react';

const Weights: React.FC = () => {
  return (
    <div>
      <h1>Control de Pesajes</h1>
      <div className="card">
        <p>Módulo de pesajes en desarrollo...</p>
        <p>Funcionalidades incluidas:</p>
        <ul>
          <li>Registro de pesajes individuales</li>
          <li>Cálculo de ganancia diaria</li>
          <li>Curvas de crecimiento</li>
          <li>Animales listos para venta</li>
        </ul>
      </div>
    </div>
  );
};

export default Weights;
